$(document).ready(function() {
    var baseUrl = window.location.origin;
    let retrive_data = baseUrl+'/seva_pooja_report_ajax';
    let edit_category = baseUrl+'/master/pooja/edit_pooja';
    var from_date = $('.from_date').val();
    var to_date = $('.to_date').val();
    var financial_year = $('.financial_year').val();
    var payment_type = $('.payment_type').val();
    get_seva_pooja_report(from_date,to_date,financial_year,payment_type);  // Call Data Table

    $('.submit_seva_pooja_report').click(function(){   // Filter Submission
        from_date = $('.from_date').val();
        to_date = $('.to_date').val();
        financial_year = $('.financial_year').val();
        payment_type = $('.payment_type').val();
        get_seva_pooja_report(from_date,to_date,financial_year,payment_type);   // Call Data Table
    });

    function get_seva_pooja_report(from_date,to_date,financial_year,payment_type)
    {
        // Initialize DataTable
        var table = $('#seva_pooja_report').DataTable({
        processing: true,
        serverSide: true,
        searching: true,
        scrollY: 500,
        scrollX: true,
        scrollCollapse: true,
        destroy: true,
        dom: 'Bfrtip', // Add Buttons extension to the DOM
        buttons: [
            {
                extend: 'excelHtml5', // Excel export button
                text: 'Export to Excel',
                filename: 'data_export', // Filename for Excel file
                //For Full Excell Download Start
                action: function (e, dt, button, config) {

                var self = this;

                dt.one('preXhr', function (e, s, data) {
                    data.length = -1; // ✅ fetch ALL records
                });

                dt.one('draw', function (e, settings) {
                    $.fn.dataTable.ext.buttons.excelHtml5.action.call(self, e, dt, button, config);
                });

                dt.ajax.reload();
            },
            // For Full Excell Downlaod Ends

                customize: function ( xlsx ) {
                    var sheet = xlsx.xl.worksheets['sheet1.xml'];
                 
                    $('c[r=A1] t', sheet).text( 'Seva Pooja Report' );
                }

            },
            {
                extend: 'pdf', // PDF export button
                text: 'Export to PDF',
                filename: 'data_export', // Filename for PDF file
                //For Full PDF Data Downlaod Start
                action: function (e, dt, button, config) {

                    var self = this;

                    // 👉 Fetch ALL records from server
                    dt.one('preXhr', function (e, s, data) {
                        data.length = -1; // ✅ VERY IMPORTANT
                    });

                    dt.one('draw', function (e, settings) {

                        // 👉 Call original PDF export
                        $.fn.dataTable.ext.buttons.pdfHtml5.action.call(self, e, dt, button, config);

                        // 👉 Reload back normal table (10 rows)
                        dt.one('preXhr', function (e, s, data) {
                            data.length = 10; // or your page length
                        });

                        setTimeout(function () {
                            dt.ajax.reload();
                        }, 100);
                    });

                    dt.ajax.reload();
                }
                //For Full PDF Data Ends
            }
        ], 
        columnDefs: [{
            "defaultContent": "-",
            "targets": 0,
            "render": function (data, type, row, meta) {
              // Return the serial number (row index + 1)
              return meta.row + 1;
            }
          }],
          
        ajax: {
            url: retrive_data,
            data:{ 
                from_date: from_date,
                to_date: to_date,
                financial_year: financial_year,
                payment_type: payment_type,
            }
        },

        "columns": [
            { "data": null }, // This column will be used for serial numbers
             
            { 
              "data": "receipt_no",  
            },
            { 
              "data": "receipt_date",
            },
            { 
              "data": "customer_name",
            },
            { 
                "data": "payment_type",
              },
              { 
                "data": "display_year",
              },
              { 
                "data": "bill_desc",
              },
              { 
                "data": "grand_total",
              },
         

        ],
    
        
    });

    }
    
});